/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP

perf = {'S': Decimal('3.0'), 'A': Decimal('2.0'), 'B': Decimal('1.0')}

def team_mult(avg):
    avg = Decimal(avg)
    if avg >= Decimal('3.5'):
        return Decimal('1.2')
    if avg >= Decimal('2.5'):
        return Decimal('1.0')
    return Decimal('0.8')

def seniority_mult(years):
    years = Decimal(years)
    if years < Decimal('1'):
        return Decimal('0.5')
    if years < Decimal('3'):
        return Decimal('0.8')
    if years < Decimal('5'):
        return Decimal('1.0')
    if years < Decimal('10'):
        return Decimal('1.2')
    return Decimal('1.5')

def round_int(value):
    return int(value.quantize(Decimal('1'), rounding=ROUND_HALF_UP))

expected = []
with open('input.csv', newline='') as f:
    for row in csv.DictReader(f):
        base = Decimal(row['base_salary'])
        months = Decimal(row['months_worked'])
        rating = row['performance']
        if rating == 'C' or months < Decimal('6'):
            bonus = 0
        else:
            raw = base * perf[rating] * team_mult(row['team_avg_score']) * seniority_mult(row['seniority_years']) * (months / Decimal('12'))
            bonus = round_int(min(raw, base * Decimal('4')))
        expected.append({'id': row['id'], 'bonus': bonus})

with open('output.json') as f:
    actual = json.load(f)

assert actual == expected, (actual, expected)
print('OK', len(actual), 'records')
PY"

